// ---- Pillar 5: Pipeline Orchestrator — keyword → full content → RAG ----
// One webhook triggers the ENTIRE content machine:
//   1) keyword-research (Google Suggest → cluster → Supabase)
//   2) content-director (article → social posts → image → newsletter)
//   3) doc-ingester (article → knowledge_base pgvector for RAG)
// Input: { keyword: '...', pillar?: 'latam|ai|gtm', skip_seo?: false }
// All sub-workflows run on localhost:5678 (no internet round-trips)
// Returns: full pipeline summary with timing for each stage
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const keyword = String(b.keyword || '').trim();
const pillar  = String(b.pillar  || 'gtm').trim();
const skipSEO = b.skip_seo === true;

if (!keyword) return [{ json: { ok: false, error: 'keyword is required' } }];

const N8N_BASE = 'http://localhost:5678/webhook';
const pipelineStart = Date.now();

async function call(path, body, timeoutMs = 120000) {
  const t0 = Date.now();
  try {
    const result = await this.helpers.httpRequest({
      method: 'POST', url: `${N8N_BASE}/${path}`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body), json: true, timeout: timeoutMs
    });
    return { ok: true, elapsed_ms: Date.now() - t0, data: result };
  } catch (e) {
    return { ok: false, elapsed_ms: Date.now() - t0, error: e.message?.slice(0, 200) };
  }
}

const stages = {};

// Stage 1: SEO keyword research (optional — enriches the keyword context)
if (!skipSEO) {
  const seoResult = await call.call(this, 'seo/keyword-research', { seeds: [keyword] }, 60000);
  stages.seo_research = { ok: seoResult.ok, elapsed_ms: seoResult.elapsed_ms, error: seoResult.error };
} else {
  stages.seo_research = { ok: true, skipped: true };
}

// Stage 2: Content Director — article + social posts + image + newsletter
const contentResult = await call.call(this, 'content/produce', { keyword, pillar, word_count: 1500 }, 180000);
stages.content_production = {
  ok: contentResult.ok,
  elapsed_ms: contentResult.elapsed_ms,
  error: contentResult.error,
  summary: contentResult.data?.summary || null
};

// Stage 3: Ingest article into RAG knowledge base (if content succeeded)
if (contentResult.ok && contentResult.data?.summary?.article?.ok) {
  // article-writer stores HTML to Supabase but doesn't return it in the response
  // fetch it directly so we can ingest the full text
  let articleText = '';
  try {
    const sbRes = await this.helpers.httpRequest({
      method: 'GET',
      url: `${ENV.SUPABASE_URL}/rest/v1/content_pipeline?keyword=eq.${encodeURIComponent(keyword)}&select=article_draft&limit=1`,
      headers: { apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}` },
      json: true, timeout: 10000
    });
    articleText = (Array.isArray(sbRes) && sbRes[0]?.article_draft) ? sbRes[0].article_draft : '';
  } catch { /* ingest with empty string — chunks_stored will be 0 */ }
  const ragResult = await call.call(this, 'ops/ingest-doc', {
    content: articleText,
    source: `markexis_blog/${keyword.replace(/\s+/g, '_')}`,
    doc_type: 'blog_article'
  }, 60000);
  stages.rag_ingestion = {
    ok: ragResult.ok,
    elapsed_ms: ragResult.elapsed_ms,
    chunks_stored: ragResult.data?.chunks_stored,
    error: ragResult.error
  };
} else {
  stages.rag_ingestion = { ok: false, skipped: true, reason: 'Content stage did not succeed' };
}

const totalElapsed = Math.round((Date.now() - pipelineStart) / 1000);
const allOk = Object.values(stages).every(s => s.ok || s.skipped);

return [{ json: {
  ok: allOk,
  keyword, pillar,
  total_elapsed_seconds: totalElapsed,
  stages,
  ran_at: new Date().toISOString()
} }];
